const data = $input.all()[0]?.json || {};
const results = data.results || [];

if (results.length === 0) {
  return [{ json: { title: 'No results found', contentSnippet: 'SearXNG returned no results for the given topic.', link: '', imageUrl: '', source: 'searxng', __noNewArticles: true } }];
}

return results.slice(0, 8).map(r => ({
  json: {
    title: String(r.title || 'Untitled'),
    contentSnippet: String(r.content || '').slice(0, 400),
    link: String(r.url || ''),
    imageUrl: '',
    source: 'searxng',
    searchQuery: String(r.title || ''),
    __noNewArticles: false,
  }
}));

const config = $('Config').first().json;
const csv = String(config.keywords_csv || '').trim();
const items = $input.all();

const kws = csv ? csv.split(',').map(k => k.trim().toLowerCase()).filter(Boolean) : [];

const filtered = kws.length === 0
  ? items
  : items.filter(item => {
      const text = (String(item.json.title || '') + ' ' + String(item.json.contentSnippet || item.json.content || '')).toLowerCase();
      return kws.some(kw => text.includes(kw));
    });

const sorted = filtered.sort((a, b) => {
  const tA = new Date(a.json.isoDate || a.json.pubDate || 0).getTime();
  const tB = new Date(b.json.isoDate || b.json.pubDate || 0).getTime();
  return tB - tA;
});

return sorted.map(i => ({ json: i.json }));

const staticData = $getWorkflowStaticData('global');
if (!staticData.seenUrls) staticData.seenUrls = {};

const now = Date.now();
const SEVEN_DAYS = 7 * 24 * 60 * 60 * 1000;

for (const url of Object.keys(staticData.seenUrls)) {
  if (now - staticData.seenUrls[url] > SEVEN_DAYS) delete staticData.seenUrls[url];
}

const fresh = [];
for (const item of $input.all()) {
  const url = String(item.json.link || item.json.guid || '').trim();
  if (!url || staticData.seenUrls[url]) continue;
  staticData.seenUrls[url] = now;
  fresh.push({ json: item.json });
}

if (fresh.length === 0) {
  return [{ json: { title: 'No new articles today', contentSnippet: 'All recent articles have already been digested.', link: '', source: 'system', __noNewArticles: true } }];
}

return fresh;

const stripBareUrls = s => s.replace(/https?:\/\/\S+/g, '').replace(/ {2,}/g, ' ').trim();

const getImageUrl = d => {
  const enc = d.enclosure;
  if (enc && typeof enc === 'object' && enc.url && /\.(jpe?g|png|gif|webp)/i.test(enc.url)) return enc.url;
  if (enc && typeof enc === 'string' && /\.(jpe?g|png|gif|webp)/i.test(enc)) return enc;
  const html = String(d.content || d['content:encoded'] || '');
  const m = html.match(/<img[^>]+src=["']([^"']+)["']/i);
  if (m && m[1] && /^https?:\/\//i.test(m[1])) return m[1];
  return '';
};

return $input.all().map(item => {
  const d = item.json;
  const title = String(d.title || 'Untitled').trim().slice(0, 200);
  const snippet = stripBareUrls(String(d.contentSnippet || d.content || d.summary || '')).slice(0, 400).trim();
  const tWords = title.split(/\s+/).filter(w => w.replace(/[^a-zA-Z]/g,'').length >= 4).slice(0, 4);
  const sWords = snippet.split(/\s+/).filter(w => w.replace(/[^a-zA-Z]/g,'').length >= 6).slice(0, 4);
  const searchQuery = [...new Set([...tWords, ...sWords])].join(' ').slice(0, 120);
  return {
    json: {
      title,
      contentSnippet: snippet,
      link: String(d.link || d.url || '').trim(),
      imageUrl: d.imageUrl || getImageUrl(d),
      source: String(d.source || 'rss'),
      searchQuery,
      __noNewArticles: Boolean(d.__noNewArticles),
    }
  };
});

const articles = $('Prepare Article').all();
const searxngItems = $input.all();
const config = $('Config').first().json;

const SYSTEM_PROMPT = `/no_think
You are a tech research digest editor. Respond with valid JSON only. No markdown, no preamble.

Rules:
- Start the summary with the subject or key fact. Never begin with "The article", "This post", or "This piece".
- No filler: do not use "underscores", "highlights", "it is worth noting", "furthermore", "notably".
- No em dashes, no ellipses, no decorative punctuation.
- Plain declarative sentences.
- Headline: specific and factual, under 80 characters, no trailing punctuation.

Schema: {"headline":"...","summary":"2-3 direct sentences","why_it_matters":"one sentence on relevance for developers and researchers"}`;

const extractDomain = u => { const m = String(u||'').match(/^https?:\/\/(?:www\.)?([^\/?#]+)/i); return m ? m[1].toLowerCase() : null; };

return articles.map((articleItem, i) => {
  const article = articleItem.json;
  let searxng = searxngItems[i]?.json || {};
  if (typeof searxng === 'string') { try { searxng = JSON.parse(searxng); } catch { searxng = {}; } }

  if (article.__noNewArticles) {
    return { json: { title: article.title, link: '', contentSnippet: '', imageUrl: '', corroborated: false, verifiedSources: [], __noNewArticles: true, llmRequestBody: { model: config.model || 'chat', messages: [{ role: 'user', content: 'Reply with exactly this JSON: {"headline":"No new articles","summary":"Nothing new today.","why_it_matters":""}' }], max_tokens: 60 } } };
  }

  const sourceHost = extractDomain(article.link) || '';
  const results = Array.isArray(searxng.results) ? searxng.results : [];
  const domains = [...new Set(results.slice(0, 10).map(r => extractDomain(r.url)).filter(d => d && d !== sourceHost))];
  const corroborated = domains.length >= 1;

  const verificationLine = corroborated
    ? 'Topic discussed across ' + domains.length + ' source' + (domains.length !== 1 ? 's' : '') + ': ' + domains.slice(0, 3).join(', ')
    : 'No external coverage found';

  return {
    json: {
      title: article.title,
      link: article.link,
      contentSnippet: article.contentSnippet,
      imageUrl: article.imageUrl || '',
      corroborated,
      verifiedSources: domains.slice(0, 3),
      __noNewArticles: false,
      llmRequestBody: {
        model: config.model || 'chat',
        messages: [
          { role: 'system', content: SYSTEM_PROMPT },
          { role: 'user', content: 'Title: ' + article.title + '\nSource: ' + article.link + '\nContent: ' + article.contentSnippet + '\nVerification: ' + verificationLine }
        ],
        temperature: 0.3,
        max_tokens: 700,
      }
    }
  };
});

const buildItems = $('Build LLM Prompt').all();
const llmItems = $input.all();

return llmItems.map((llmItem, i) => {
  const upstream = buildItems[i]?.json || {};
  const llmResponse = llmItem.json;

  if (upstream.__noNewArticles) {
    return { json: { headline: 'No New Articles Today', summary: 'All recent articles have already been digested.', why_it_matters: '', link: '', imageUrl: '', corroborated: true, verifiedSources: [], __noNewArticles: true } };
  }

  let parsed;
  try {
    const raw = String(llmResponse?.choices?.[0]?.message?.content || '');
    const match = raw.match(/\{[\s\S]*\}/);
    parsed = JSON.parse(match ? match[0] : raw.trim());
  } catch {
    parsed = { headline: upstream.title || 'Article', summary: upstream.contentSnippet || 'Summary unavailable.', why_it_matters: '' };
  }

  return { json: {
    headline: String(parsed.headline || upstream.title || 'Article').slice(0, 80),
    summary: String(parsed.summary || upstream.contentSnippet || ''),
    why_it_matters: String(parsed.why_it_matters || ''),
    link: String(upstream.link || ''),
    imageUrl: String(upstream.imageUrl || ''),
    corroborated: Boolean(upstream.corroborated),
    verifiedSources: Array.isArray(upstream.verifiedSources) ? upstream.verifiedSources : [],
  }};
});

const aggregated = $input.all()[0]?.json || {};
const articles = aggregated.allArticles || [];

const dateStr = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

const GREEN = 3066993;
const BLUE  = 3447003;

const realArticles = articles.filter(a => !a.__noNewArticles);
const noNew = realArticles.length === 0;

const embeds = realArticles.slice(0, 10).map(a => {
  const summary = String(a.summary || '').slice(0, 280);
  const wim = String(a.why_it_matters || '').slice(0, 160);
  const desc = wim ? summary + '\n\n**Why it matters:** ' + wim : summary;

  const embed = {
    title: String(a.headline || 'Article').slice(0, 256),
    description: desc,
    color: a.corroborated ? GREEN : BLUE,
    footer: {
      text: a.corroborated
        ? 'Verified: ' + (a.verifiedSources || []).join(', ')
        : 'Single source'
    }
  };
  if (a.link) embed.url = a.link;
  if (a.imageUrl) embed.thumbnail = { url: a.imageUrl };
  return embed;
});

const header = noNew
  ? 'Daily Tech Digest - ' + dateStr + '\nNo new articles today.'
  : 'Daily Tech Digest - ' + dateStr + ' | ' + embeds.length + ' article' + (embeds.length !== 1 ? 's' : '');

const payload = { content: header };
if (embeds.length > 0) payload.embeds = embeds;

return [{ json: payload }];
